    private long getRowCount(SessionLocal session, boolean approximation) {
        switch (type) {
        case INFORMATION_SCHEMA_CATALOG_NAME:
            return 1L;
        case COLLATIONS: {
            Locale[] locales = CompareMode.getCollationLocales(approximation);
            if (locales != null) {
                return locales.length + 1;
            }
            break;
        }
        case SCHEMATA:
            return session.getDatabase().getAllSchemas().size();
        case IN_DOUBT:
            if (session.getUser().isAdmin()) {
                ArrayList<InDoubtTransaction> inDoubt = session.getDatabase().getInDoubtTransactions();
                if (inDoubt != null) {
                    return inDoubt.size();
                }
            }
            return 0L;
        case ROLES:
            if (session.getUser().isAdmin()) {
                long count = 0L;
                for (RightOwner rightOwner : session.getDatabase().getAllUsersAndRoles()) {
                    if (rightOwner instanceof Role) {
                        count++;
                    }
                }
                return count;
            }
            break;
        case SESSIONS:
            if (session.getUser().isAdmin()) {
                return session.getDatabase().getSessionCount();
            } else {
                return 1L;
            }
        case USERS:
            if (session.getUser().isAdmin()) {
                long count = 0L;
                for (RightOwner rightOwner : session.getDatabase().getAllUsersAndRoles()) {
                    if (rightOwner instanceof User) {
                        count++;
                    }
                }
                return count;
            } else {
                return 1L;
            }
        }
        if (approximation) {
            return ROW_COUNT_APPROXIMATION;
        }
        throw DbException.getInternalError(toString());
    }

    public synchronized long getRowCount(SessionLocal session) {
        //The foo alias is used to support the PostgreSQL syntax
        String sql = "SELECT COUNT(*) FROM " + qualifiedTableName + " as foo";
        try {
            PreparedStatement prep = execute(sql, null, false, session);
            ResultSet rs = prep.getResultSet();
            rs.next();
            long count = rs.getLong(1);
            rs.close();
            reusePreparedStatement(prep, sql);
            return count;
        } catch (Exception e) {
            throw wrapException(sql, e);
        }
    }

